#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *buf;
    int head, tail, size, capacity;
} RingBuffer;

RingBuffer *rb_create(int cap) {
    RingBuffer *rb = malloc(sizeof(RingBuffer));
    rb->buf = malloc(cap * sizeof(int));
    rb->head = rb->tail = rb->size = 0;
    rb->capacity = cap;
    return rb;
}

int rb_put(RingBuffer *rb, int val) {
    if (rb->size == rb->capacity) return 0;
    rb->buf[rb->tail] = val;
    rb->tail = (rb->tail + 1) % rb->capacity;
    rb->size++;
    return 1;
}

int rb_get(RingBuffer *rb, int *val) {
    if (rb->size == 0) return 0;
    *val = rb->buf[rb->head];
    rb->head = (rb->head + 1) % rb->capacity;
    rb->size--;
    return 1;
}

int main() {
    RingBuffer *rb = rb_create(4);
    rb_put(rb, 10); rb_put(rb, 20); rb_put(rb, 30);
    int v;
    while (rb_get(rb, &v)) printf("%d ", v);
    printf("\n");
    free(rb->buf); free(rb);
    return 0;
}

