void to_binary(unsigned int n, char *buf) {
    int i = 0;
    if (n == 0) { buf[0] = '0'; buf[1] = '\0'; return; }
    while (n > 0) {
        buf[i++] = '0' + (n & 1);
        n >>= 1;
    }
    buf[i] = '\0';
    // reverse
    for (int j = 0, k = i-1; j < k; j++, k--) {
        char t = buf[j]; buf[j] = buf[k]; buf[k] = t;
    }
}

