#define HEAP_MAX 100
typedef struct { int data[HEAP_MAX]; int size; } MinHeap;

void heap_push(MinHeap *h, int val) {
    int i = h->size++;
    h->data[i] = val;
    while (i > 0) {
        int p = (i - 1) / 2;
        if (h->data[p] <= h->data[i]) break;
        int t = h->data[p]; h->data[p] = h->data[i]; h->data[i] = t;
        i = p;
    }
}

int heap_pop(MinHeap *h) {
    int top = h->data[0];
    h->data[0] = h->data[--(h->size)];
    int i = 0;
    while (1) {
        int l = 2*i+1, r = 2*i+2, m = i;
        if (l < h->size && h->data[l] < h->data[m]) m = l;
