#define TABLE_SIZE 16

typedef struct Entry { char *key; int value; struct Entry *next; } Entry;
Entry *table[TABLE_SIZE];

unsigned int hash(const char *key) {
    unsigned int h = 0;
    while (*key) h = h * 31 + (unsigned char)*key++;
    return h % TABLE_SIZE;
}

void ht_put(const char *key, int val) {
    unsigned int idx = hash(key);
    Entry *e = malloc(sizeof(Entry));
    e->key = strdup(key); e->value = val; e->next = table[idx];
    table[idx] = e;
}

int ht_get(const char *key) {
    unsigned int idx = hash(key);
    for (Entry *e = table[idx]; e; e = e->next)
        if (strcmp(e->key, key) == 0) return e->value;
    return -1;
}

int main() {
    ht_put("alpha", 1); ht_put("beta", 2); ht_put("gamma", 3);
    printf("alpha=%d beta=%d gamma=%d\n", ht_get("alpha"), ht_get("beta"), ht_get("gamma"));
